// Statistics tracking for cache
class CacheStatistics implements Serializable {
    private static final long serialVersionUID = 1L;
    private long hits;
    private long misses;
    private long evictions;
    private long diskReads;
    private long diskWrites;

    public synchronized void recordHit() { hits++; }
    public synchronized void recordMiss() { misses++; }
    public synchronized void recordEviction() { evictions++; }
    public synchronized void recordDiskRead() { diskReads++; }
    public synchronized void recordDiskWrite() { diskWrites++; }

    public long getHits() { return hits; }
    public long getMisses() { return misses; }
    public long getEvictions() { return evictions; }
    public long getDiskReads() { return diskReads; }
    public long getDiskWrites() { return diskWrites; }

    public double getHitRate() {
        long total = hits + misses;
        return total == 0 ? 0.0 : (double) hits / total;
    }

    @Override
    public String toString() {
        return String.format("CacheStatistics{hits=%d, misses=%d, evictions=%d, diskReads=%d, diskWrites=%d, hitRate=%.2f%%}",
                hits, misses, evictions, diskReads, diskWrites, getHitRate() * 100);
    }
}

// Main disk-backed cache system
class DiskCache {
    private final Path cacheDirectory;
    private final ConcurrentHashMap<String, CacheEntry<?>> memoryCache;
    private final ReadWriteLock lock;
    private final int maxMemoryEntries;
    private final long defaultTtlMillis;
    private final CacheStatistics statistics;
    private final ScheduledExecutorService cleanupExecutor;

    public DiskCache(String cacheDir, int maxMemoryEntries, long defaultTtlMillis) throws IOException {
        this.cacheDirectory = Paths.get(cacheDir);
        this.maxMemoryEntries = maxMemoryEntries;
        this.defaultTtlMillis = defaultTtlMillis;
        this.memoryCache = new ConcurrentHashMap<>();
        this.lock = new ReentrantReadWriteLock();
        this.statistics = new CacheStatistics();

        Files.createDirectories(cacheDirectory);

        // Schedule periodic cleanup of expired entries
        this.cleanupExecutor = Executors.newSingleThreadScheduledExecutor(r -> {
            Thread t = new Thread(r, "cache-cleanup");
            t.setDaemon(true);
            return t;
        });
        cleanupExecutor.scheduleAtFixedRate(this::cleanupExpired, 60, 60, TimeUnit.SECONDS);
    }

    public <T extends Serializable> void put(String key, T value) {
        put(key, value, defaultTtlMillis);
    }

    public <T extends Serializable> void put(String key, T value, long ttlMillis) {
        lock.writeLock().lock();
        try {
            CacheEntry<T> entry = new CacheEntry<>(key, value, ttlMillis);

            // Evict from memory if at capacity
            if (memoryCache.size() >= maxMemoryEntries && !memoryCache.containsKey(key)) {
                evictOldestFromMemory();
            }

            memoryCache.put(key, entry);

            // Also persist to disk
            writeToDisk(key, entry);
        } finally {
            lock.writeLock().unlock();
        }
    }

    @SuppressWarnings("unchecked")
    public <T extends Serializable> Optional<T> get(String key) {
        lock.readLock().lock();
        try {
            // Check memory cache first
            CacheEntry<?> entry = memoryCache.get(key);
            if (entry != null) {
                if (entry.isExpired()) {
                    lock.readLock().unlock();
                    remove(key);
                    lock.readLock().lock();
                    statistics.recordMiss();
                    return Optional.empty();
                }
                statistics.recordHit();
                return Optional.of((T) entry.getValue());
            }

            // Fallback to disk
            entry = readFromDisk(key);
            if (entry != null) {
                if (entry.isExpired()) {
                    lock.readLock().unlock();
                    remove(key);
                    lock.readLock().lock();
                    statistics.recordMiss();
                    return Optional.empty();
                }

                // Promote to memory cache
                lock.readLock().unlock();
                lock.writeLock().lock();
                try {
                    if (memoryCache.size() >= maxMemoryEntries) {
                        evictOldestFromMemory();
                    }
                    memoryCache.put(key, entry);
                } finally {
                    lock.writeLock().unlock();
                    lock.readLock().lock();
                }

                statistics.recordHit();
                return Optional.of((T) entry.getValue());
            }

            statistics.recordMiss();
            return Optional.empty();
        } finally {
            lock.readLock().unlock();
        }
    }

    public void remove(String key) {
        lock.writeLock().lock();
        try {
            memoryCache.remove(key);
            deleteFromDisk(key);
        } finally {
            lock.writeLock().unlock();
        }
    }

    public boolean containsKey(String key) {
        lock.readLock().lock();
        try {
            if (memoryCache.containsKey(key)) {
                CacheEntry<?> entry = memoryCache.get(key);
                return entry != null && !entry.isExpired();
            }
            Path file = getCacheFilePath(key);
            return Files.exists(file);
        } finally {
            lock.readLock().unlock();
        }
    }

    public void clear() {
        lock.writeLock().lock();
        try {
            memoryCache.clear();
            try (DirectoryStream<Path> stream = Files.newDirectoryStream(cacheDirectory, "*.cache")) {
                for (Path file : stream) {
                    Files.deleteIfExists(file);
                }
            } catch (IOException e) {
                System.err.println("Error clearing disk cache: " + e.getMessage());
            }
        } finally {
            lock.writeLock().unlock();
        }
    }

    public int memorySize() {
        return memoryCache.size();
    }

    public long diskSize() {
        try (DirectoryStream<Path> stream = Files.newDirectoryStream(cacheDirectory, "*.cache")) {
            long count = 0;
            for (Path ignored : stream) count++;
            return count;
        } catch (IOException e) {
            return -1;
        }
    }

    public CacheStatistics getStatistics() {
        return statistics;
    }

    public void shutdown() {
        cleanupExecutor.shutdown();
        try {
            cleanupExecutor.awaitTermination(5, TimeUnit.SECONDS);
        } catch (InterruptedException e) {
            Thread.currentThread().interrupt();
        }
    }

    // Compute if absent - caches expensive computation results
    @SuppressWarnings("unchecked")
    public <T extends Serializable> T computeIfAbsent(String key, Callable<T> computation) throws Exception {
        Optional<T> cached = get(key);
        if (cached.isPresent()) {
            return cached.get();
        }

        T result = computation.call();
        put(key, result);
        return result;
    }

    public <T extends Serializable> T computeIfAbsent(String key, long ttlMillis, Callable<T> computation) throws Exception {
        Optional<T> cached = get(key);
        if (cached.isPresent()) {
            return cached.get();
        }

        T result = computation.call();
        put(key, result, ttlMillis);
        return result;
    }

    // --- Private helpers ---

    private void writeToDisk(String key, CacheEntry<?> entry) {
        Path filePath = getCacheFilePath(key);
        try (ObjectOutputStream oos = new ObjectOutputStream(
                new BufferedOutputStream(new FileOutputStream(filePath.toFile())))) {
            oos.writeObject(entry);
            oos.flush();
            statistics.recordDiskWrite();
        } catch (IOException e) {
            System.err.println("Error writing cache entry to disk [" + key + "]: " + e.getMessage());
        }
    }

    private CacheEntry<?> readFromDisk(String key) {
        Path filePath = getCacheFilePath(key);
        if (!Files.exists(filePath)) {
            return null;
        }
        try (ObjectInputStream ois = new ObjectInputStream(
                new BufferedInputStream(new FileInputStream(filePath.toFile())))) {
            statistics.recordDiskRead();
            return (CacheEntry<?>) ois.readObject();
        } catch (IOException | ClassNotFoundException e) {
            System.err.println("Error reading cache entry from disk [" + key + "]: " + e.getMessage());
            // Corrupted file - delete it
            try { Files.deleteIfExists(filePath); } catch (IOException ignored) {}
            return null;
        }
    }

    private void deleteFromDisk(String key) {
        try {
            Files.deleteIfExists(getCacheFilePath(key));
        } catch (IOException e) {
            System.err.println("Error deleting cache file [" + key + "]: " + e.getMessage());
        }
    }

    private Path getCacheFilePath(String key) {
        // Sanitize key for filename
        String safeKey = key.replaceAll("[^a-zA-Z0-9._-]", "_");
        return cacheDirectory.resolve(safeKey + ".cache");
    }

    private void evictOldestFromMemory() {
        String oldestKey = null;
        long oldestTime = Long.MAX_VALUE;

        for (Map.Entry<String, CacheEntry<?>> e : memoryCache.entrySet()) {
            if (e.getValue().getCreatedAt() < oldestTime) {
                oldestTime = e.getValue().getCreatedAt();
                oldestKey = e.getKey();
            }
        }

        if (oldestKey != null) {
            memoryCache.remove(oldestKey);
            statistics.recordEviction();
            System.out.println("  [Cache] Evicted from memory: " + oldestKey);
        }
    }

    private void cleanupExpired() {
        lock.writeLock().lock();
        try {
            // Clean memory
            List<String> expiredKeys = new ArrayList<>();
            for (Map.Entry<String, CacheEntry<?>> e : memoryCache.entrySet()) {
                if (e.getValue().isExpired()) {
                    expiredKeys.add(e.getKey());
                }
            }
            for (String key : expiredKeys) {
                memoryCache.remove(key);
                deleteFromDisk(key);
                System.out.println("  [Cache Cleanup] Removed expired entry: " + key);
            }

            // Clean disk entries not in memory
            try (DirectoryStream<Path> stream = Files.newDirectoryStream(cacheDirectory, "*.cache")) {
                for (Path file : stream) {
                    String filename = file.getFileName().toString();
                    String key = filename.substring(0, filename.length() - ".cache".length());
                    if (!memoryCache.containsKey(key)) {
                        CacheEntry<?> entry = readFromDisk(key);
                        if (entry != null && entry.isExpired()) {
                            Files.deleteIfExists(file);
                        }
                    }
                }
            } catch (IOException e) {
                System.err.println("Error during disk cleanup: " + e.getMessage());
            }
        } finally {
            lock.writeLock().unlock();
        }
    }
}

// Main demonstration class
public class CachingSystem {

    // Simulate expensive computation
    private static ComputationResult expensiveComputation(String id, List<String> params) {
        System.out.println("  >> Performing expensive computation for: " + id);
        long start = System.currentTimeMillis();

        // Simulate heavy work
        Map<String, Double> results = new HashMap<>();
        double sum = 0;
        for (int i = 0; i < 1_000_000; i++) {
            sum += Math.sin(i) * Math.cos(i);
        }
        results.put("primaryResult", sum);
        results.put("iterations", 1_000_000.0);
        results.put("mean", sum / 1_000_000);

        long elapsed = System.currentTimeMillis() - start;
        return new ComputationResult(id, "sin-cos-aggregate", params, results, elapsed);
    }

    public static void main(String[] args) {
        try {
            System.out.println("=== Disk-Backed Caching System Demo ===\n");

            // Create cache: max 5 entries in memory, 5-minute default TTL
            DiskCache cache = new DiskCache("./cache_data", 5, 5 * 60 * 1000);

            // --- 1. Cache User Preferences ---
            System.out.println("--- Caching User Preferences ---");
            UserPreferences prefs1 = new UserPreferences("user-001");
            prefs1.setTheme("dark");
            prefs1.setLanguage("en-US");
            prefs1.addCustomSetting("fontSize", "14");
            prefs1.addCustomSetting("sidebar", "collapsed");
            prefs1.addFavoriteCategory("Technology");
            prefs1.addFavoriteCategory("Science");
            prefs1.setNotificationsEnabled(true);

            cache.put("prefs:user-001", prefs1);
            System.out.println("Stored: " + prefs1);

            UserPreferences prefs2 = new UserPreferences("user-002");
            prefs2.setTheme("light");
            prefs2.setLanguage("fr-FR");
            prefs2.addCustomSetting("fontSize", "16");
            prefs2.addFavoriteCategory("Art");
            cache.put("prefs:user-002", prefs2);
            System.out.println("Stored: " + prefs2);

            // Retrieve
            Optional<UserPreferences> retrieved = cache.get("prefs:user-001");
            retrieved.ifPresent(p -> System.out.println("Retrieved: " + p));

            // --- 2. Cache Session Data ---
            System.out.println("\n--- Caching Session Data ---");
            SessionData session1 = new SessionData("sess-abc123", "user-001", "192.168.1.100");
            session1.setUserAgent("Mozilla/5.0");
            session1.addVisitedPage("/home");
            session1.addVisitedPage("/dashboard");
            session1.addVisitedPage("/settings");
            session1.setAttribute("cart_items", 3);
            session1.setAttribute("last_search", "java caching");

            cache.put("session:sess-abc123", session1, 30 * 60 * 1000); // 30 min TTL
            System.out.println("Stored: " + session1);

            SessionData session2 = new SessionData("sess-def456", "user-002", "10.0.0.50");
            session2.setUserAgent("Chrome/120.0");
            session2.addVisitedPage("/login");
            session2.addVisitedPage("/profile");
            session2.setAttribute("theme_override", "compact");

            cache.put("session:sess-def456", session2, 30 * 60 * 1000);
            System.out.println("Stored: " + session2);

            Optional<SessionData> retrievedSession = cache.get("session:sess-abc123");
            retrievedSession.ifPresent(s -> System.out.println("Retrieved: " + s));

            // --- 3. Cache Expensive Computation Results ---
            System.out.println("\n--- Caching Expensive Computations ---");

            // First call - actually computes
            long start = System.currentTimeMillis();
            ComputationResult result1 = cache.computeIfAbsent("compute:analysis-1",
                    () -> expensiveComputation("analysis-1", Arrays.asList("param1", "param2")));
            long firstCallTime = System.currentTimeMillis() - start;
            System.out.println("First call result: " + result1);
            System.out.println("First call total time: " + firstCallTime + "ms");

            // Second call - from cache (much faster)
            start = System.currentTimeMillis();
            ComputationResult result2 = cache.computeIfAbsent("compute:analysis-1",
                    () -> expensiveComputation("analysis-1", Arrays.asList("param1", "param2")));
            long secondCallTime = System.currentTimeMillis() - start;
            System.out.println("Cached call result: " + result2);
            System.out.println("Cached call total time: " + secondCallTime + "ms");
            System.out.println("Speedup: " + (firstCallTime > 0 ? (double) firstCallTime / Math.max(secondCallTime, 1) : "N/A") + "x");

            // Another expensive computation
            ComputationResult result3 = cache.computeIfAbsent("compute:analysis-2", 10 * 60 * 1000,
                    () -> expensiveComputation("analysis-2", Arrays.asList("alpha", "beta", "gamma")));
            System.out.println("Second computation: " + result3);

            // --- 4. Cache with TTL expiration ---
            System.out.println("\n--- TTL Expiration Demo ---");
            cache.put("temp:short-lived", "This will expire soon", 2000); // 2 second TTL
            Optional<String> beforeExpiry = cache.get("temp:short-lived");
            System.out.println("Before expiry: " + beforeExpiry.orElse("NOT FOUND"));

            System.out.println("Waiting 2.5 seconds for expiry...");
            Thread.sleep(2500);

            Optional<String> afterExpiry = cache.get("temp:short-lived");
            System.out.println("After expiry: " + afterExpiry.orElse("NOT FOUND (expired)"));

            // --- 5. Memory eviction demo ---
            System.out.println("\n--- Memory Eviction Demo (max 5 memory entries) ---");
            for (int i = 1; i <= 8; i++) {
                UserPreferences p = new UserPreferences("bulk-user-" + i);
                p.setTheme("theme-" + i);
                cache.put("bulk:user-" + i, p);
                System.out.println("  Added bulk:user-" + i + " | Memory size: " + cache.memorySize());
            }

            // Entry evicted from memory should still be on disk
            System.out.println("\nRetrieving evicted entry from disk...");
            Optional<UserPreferences> fromDisk = cache.get("bulk:user-1");
            fromDisk.ifPresent(p -> System.out.println("Retrieved from disk: " + p));

            // --- 6. Show statistics ---
            System.out.println("\n--- Cache Statistics ---");
            System.out.println(cache.getStatistics());
            System.out.println("Memory entries: " + cache.memorySize());
            System.out.println("Disk entries: " + cache.diskSize());

            // --- 7. Contains and remove ---
            System.out.println("\n--- Contains & Remove Demo ---");
            System.out.println("Contains 'prefs:user-001': " + cache.containsKey("prefs:user-001"));
            cache.remove("prefs:user-001");
            System.out.println("After remove, contains 'prefs:user-001': " + cache.containsKey("prefs:user-001"));

            // --- 8. Clear all ---
            System.out.println("\n--- Clearing Cache ---");
            cache.clear();
            System.out.println("After clear - Memory: " + cache.memorySize() + ", Disk: " + cache.diskSize());

            // Final statistics
            System.out.println("\n--- Final Statistics ---");
            System.out.println(cache.getStatistics());

            cache.shutdown();
            System.out.println("\nCache system shut down successfully.");

        } catch (Exception e) {
            e.printStackTrace();
        }
    }
}